INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$06a0ea68-a658-4f35-b774-14b59c955f03$tag$, $tag$2026021900054$tag$, $tag$Leonardo (5583998939911)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"19/02/2026 11:17:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia!!","time":"19/02/2026 11:27:25"},{"role":"client","text":"Até quando posso fazer a matrícula nesse semestre? Teologia","time":"19/02/2026 11:27:31"},{"role":"client","text":"E gostaria de saber sobre os cursos livres disponíveis","time":"19/02/2026 11:27:58"},{"role":"agent","text":"*Thayanne Sales:* https://cursos.ficv.edu.br/super_live_ficv/","time":"19/02/2026 11:34:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Até março","time":"19/02/2026 11:34:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/02/2026 11:34:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"19/02/2026 11:34:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/02/2026 11:35:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"19/02/2026 11:35:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Como ficam as aulas que estão em atraso?","time":"19/02/2026 11:43:52"},{"role":"agent","text":"*Thayanne Sales:* As aulas são gravadas e você pode assistir a qualquer hora do seu dia, só as avaliações que tem datas especificas para fazer, que estão todas as informações na plataforma. ","time":"19/02/2026 11:47:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"19/02/2026 11:51:19"},{"role":"client","text":"Quantas horas por dia de aula para encerrar o semestre a tempo?","time":"19/02/2026 11:51:36"},{"role":"client","text":"Tem um desconto maior pra quem participa da igreja do cidade viva?","time":"19/02/2026 11:52:00"},{"role":"agent","text":"*Thayanne Sales:* Recomendamos  1h ","time":"19/02/2026 11:52:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Sim, 10 % a mais, totalizando 30% de desconto","time":"19/02/2026 11:53:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"19/02/2026 11:55:42"},{"role":"client","text":"O pagamento em boleto pode ser para o dia 05?","time":"19/02/2026 11:55:53"},{"role":"client","text":"Da primeira mensalidade?","time":"19/02/2026 11:55:59"},{"role":"client","text":"Estou muito interessado em iniciar o curso","time":"19/02/2026 11:56:12"},{"role":"client","text":"Assisti a primeira aula presencial com o professor Jorge Noda","time":"19/02/2026 11:56:25"},{"role":"client","text":"Mas pretendo começar EAD","time":"19/02/2026 11:56:35"},{"role":"agent","text":