INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$7394e10d-5101-44d6-99d1-39e14de3b8e5$tag$, $tag$2026021900062$tag$, $tag$Muller Miranda (5583988267001)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"19/02/2026 11:28:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá","time":"19/02/2026 11:59:37"},{"role":"client","text":"Bom dia","time":"19/02/2026 11:59:39"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu interesse por um dos nossos cursos vindo do Congresso Consciência Cristã e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\n\nQual o curso deseja informações?","time":"19/02/2026 12:00:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Teologia ead","time":"19/02/2026 12:22:51"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"19/02/2026 13:34:15","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* \nA nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/02/2026 13:34:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"19/02/2026 13:34:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/02/2026 13:35:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"19/02/2026 13:35:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"20/02/2026 08:10:49","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMuller Miranda, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 14:15:22"}]$tag$, $tag$2026-02-19 11:28:01+00$tag$, FALSE, FALSE, 7.6, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 7, 2, 9, 8, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$6f3e7b66-cf71-4d2f-ad3e-0b526fafb44b$tag$, $tag$2026021900066$tag$, $tag$Cellyna (5567998369648)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"19/02/2026 11:38:02"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"19/02/2026 11:38:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 11:44:31"},{"role":"agent","text":"*Karina Pimentel:* \nTeologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"19/02/2026 11:45:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/02/2026 11:45:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi bom dia, estou querendo muito fazer um curso de teologia","time":"19/02/2026 11:55:52"},{"role":"client","text":"Mas vou ver a possibilidade financeira neste momento. Mas se não conseguir começar agora vou me organizar para iniciar no semestre que vem","time":"19/02/2026 11:58:08"},{"role":"client","text":"Obrigada pelas informações","time":"19/02/2026 11:58:18"},{"role":"client","text":"Eu sou de Campo Grande MS","time":"19/02/2026 11:58:36"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"20/02/2026 08:26:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"20/02/2026 08:26:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar o requerimento de descontos ok!","time":"20/02/2026 08:26:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* https://bit.ly/RequerimentodeDescontoFICV","time":"20/02/2026 08:27:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nCellyna, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 18:17:05"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"22/02/2026 11:56:38"},{"role":"client","text":"Sua sessão expirou!","time":"22/02/2026 11:58:39"}]$tag$, $tag$2026-02-19 11:38:02+00$tag$, FALSE, FALSE, 6.8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 3, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d186e965-4b35-4a10-81ae-803458e6e19b$tag$, $tag$2026021900080$tag$, $tag$Tamires (5511987739439)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde!","time":"19/02/2026 12:36:23"},{"role":"client","text":"🌟 Boa tarde Tamires! Que alegria ter você aqui com a gente! 🙌","time":"19/02/2026 12:36:24"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/02/2026 12:36:28"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/02/2026 12:36:32"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/02/2026 12:36:39"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/02/2026 12:36:51"},{"role":"client","text":"Olá! Tamires!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/02/2026 12:36:51"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/02/2026 12:36:55"},{"role":"client","text":"Falar com um atendente","time":"19/02/2026 12:37:08"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"19/02/2026 12:37:09"},{"role":"client","text":"Eu gostaria de saber se a minha inscrição para o curso de psicopedagogia foi realizada e também se o diploma da pós em educação clássica doi emitido.\nEnviei os documentos por e-mail faz algum tempo.","time":"19/02/2026 12:38:18"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/02/2026 13:16:05"},{"role":"client","text":"Eu gostaria de saber se a minha inscrição para o curso de psicopedagogia foi realizada e também se o diploma da pós em educação clássica doi emitido.\nEnviei os documentos por e-mail faz algum tempo.","time":"19/02/2026 13:35:48"},{"role":"client","text":"Oi, boa tarde!","time":"19/02/2026 16:11:24"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/02/2026 16:11:35"},{"role":"agent","text":"*Karina Pimentel:* Qual seu nome completo por gentileza?","time":"19/02/2026 18:30:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Tamires de Almeida Brandalise","time":"19/02/2026 18:32:46"},{"role":"client","text":"Karina, eu não sei o que se passa com o atendimento de vocês! Quando eu entrava em contato, sempre era atendida com agilidade e praticidade, agora demora horas para retornar quando não só no outro dia.\nEstou desapontada, isso é cansativo.","time":"19/02/2026 18:35:37"},{"role":"agent","text":"*Karina Pimentel:* Passamos por uma mudança de sistema e ocorreu um atraso nos atendimentos, pedimos desculpas!","time":"19/02/2026 18:37:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Me confirme por gentileza, a senhora chegou a pagar a inscrição do novo curso?","time":"19/02/2026 18:38:00","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Eu fiz o que o sistema pediu, naquele link de inscrição, mas não recebi nada por email, fiquei sem entender, inclusive se tinha dado certo.","time":"19/02/2026 18:38:59"},{"role":"agent","text":"*Karina Pimentel:* Certo!\n","time":"19/02/2026 18:50:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"Arquivo de áudio | (https://