INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f460c6cb-7f08-41ae-afcc-32a6bdd6b79b$tag$, $tag$2026022000051$tag$, $tag$🫶🏻 (5512988604827)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"20/02/2026 10:22:59"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"20/02/2026 10:23:00"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 10:28:04"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"20/02/2026 10:28:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"20/02/2026 10:28:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"20/02/2026 10:29:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/02/2026 10:30:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 10:31:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\n🫶🏻, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/02/2026 08:17:51"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"23/02/2026 10:26:05"},{"role":"client","text":"Sua sessão expirou!","time":"23/02/2026 10:28:07"}]$tag$, $tag$2026-02-20 10:22:59+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:42:01.563441+00$tag$, 7, 10, 5, 2, 9, 5, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bdba929a-2ed9-4a51-b1fa-dd4892db4098$tag$, $tag$2026022000052$tag$, $tag$Leticia Duarte (5511988774202)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia","time":"20/02/2026 10:23:31"},{"role":"client","text":"🌟 Bom dia Leticia Duarte! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 10:23:32"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 10:23:35"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 10:23:39"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/02/2026 10:23:43"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/02/2026 10:23:49"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/02/2026 10:23:54"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/02/2026 10:23:55"},{"role":"client","text":"Sim, concordo","time":"20/02/2026 10:25:05"},{"role":"client","text":"✅ Obrigado, Leticia Duarte! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"20/02/2026 10:25:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 10:25:10"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 10:25:21"},{"role":"client","text":"Olá! Leticia Duarte!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 10:25:21"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 10:25:25"},{"role":"client","text":"Saber sobre os cursos","time":"20/02/2026 10:25:43"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/02/2026 10:25:47"},{"role":"client","text":"Graduação","time":"20/02/2026 10:25:59"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"20/02/2026 10:26:03"},{"role":"client","text":"Teologia (EAD)","time":"20/02/2026 10:26:15"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"20/02/2026 10:26:16"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/02/2026 10:26:20"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/02/2026 10:26:34"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/02/2026 10:26:35"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 10:28:14"},{"role":"ag