INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$7e14a6d0-be4a-452a-b5f1-ec599c370d91$tag$, $tag$2026022000070$tag$, $tag$Keny Correia (5583988353346)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"20/02/2026 10:56:59"},{"role":"client","text":"🌟 Bom dia Keny Correia! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 10:57:00"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 10:57:04"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 10:57:08"},{"role":"client","text":"Tenho interesse não os de Psicoteologia","time":"20/02/2026 10:57:13"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 10:57:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 10:57:34"},{"role":"client","text":"Olá! Keny Correia!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 10:57:36"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 10:57:40"},{"role":"client","text":"Saber sobre os cursos","time":"20/02/2026 10:57:50"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/02/2026 10:57:54"},{"role":"client","text":"Pós-Graduação","time":"20/02/2026 10:58:05"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"20/02/2026 10:58:09"},{"role":"client","text":"Psicoteologia","time":"20/02/2026 10:58:25"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"20/02/2026 10:58:26"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/02/2026 10:58:29"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/02/2026 10:59:04"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/02/2026 10:59:05"},{"role":"client","text":"Ok","time":"20/02/2026 10:59:17"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 11:05:01"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"20/02/2026 11:05:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"20/02/2026 11:05:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Disciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"20/02/2026 11:05:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para Março/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 11:05:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está com  uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"20/02/2026 11:05:54","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Vou organizar as fumaças e entro em contato. Obg","time":"20/02/2026 11:06:47"},{"role":"agent","text":"*Thayanne Sales:* Compreendo","time":"20/02/2026 11:07:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"20/02/2026 11:07:07","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não","time":"20/02/2026 11:07:21"},{"role":"client","text":"Obg","time":"20/02/2026 11:07:22"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo final de semana ","time":"20/02/2026 11:07:49","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nKeny Correia, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 11:07:55"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 11:07:56"},{"role":"client","text":"5","time":"20/02/2026 11:08:11"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"20/02/2026 11:08:12"},{"role":"client","text":"Keny Correia, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"20/02/2026 11:23:13"}]$tag$, $tag$2026-02-20 10:56:59+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 8, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$36f32dbd-adb3-43bd-9a72-3a30977016ff$tag$, $tag$2026022000071$tag$, $tag$Amanda Rangel Mendonça (5531984415203)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia! Gostaria de saber mais informações sobre a pós graduação em educação cristã clássica.","time":"20/02/2026 10:58:21"},{"role":"client","text":"🌟 Bom dia Amanda Rangel Mendonça! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 10:58:22"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 10:58:25"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 10:58:29"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/02/2026 10:58:33"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/02/2026 10:58:39"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/02/2026 10:58:45"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/02/2026 10:58:46"},{"role":"client","text":"Sim, concordo","time":"20/02/2026 11:00:00"},{"role":"client","text":"✅ Obrigado, Amanda Rangel Mendonça! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"20/02/2026 11:00:00"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 11:00:04"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 11:00:16"},{"role":"client","text":"Olá! Amanda Rangel Mendonça!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 11:00:18"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 11:00:22"},{"role":"client","text":"Saber sobre os cursos","time":"20/02/2026 11:01:37"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/02/2026 11:01:41"},{"role":"client","text":"Pós-Graduação","time":"20/02/2026 11:02:07"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"20/02/2026 11:02:11"},{"role":"client","text":"Educação Cristã Clássica","time":"20/02/2026 11:02:23"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"20/02/2026 11:02:24"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/02/2026 11:02:28"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/02/2026 11:02:41"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/02/2026 11:02:42"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 11:06:04"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"20/02/2026 11:06:22","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"20/02/2026 11:06:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"20/02/2026 11:06:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.\n","time":"20/02/2026 11:06:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"20/02/2026 11:06:50","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá, Thayanne! Tudo bem? O início da pós é imeditado?","time":"20/02/2026 11:08:42"},{"role":"agent","text":"*Thayanne Sales:* Não","time":"20/02/2026 11:09:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ah, acabei de ver que é em abril","time":"20/02/2026 11:09:21"},{"role":"agent","text":"*Thayanne Sales:* Inicio das aulas em Abril","time":"20/02/2026 11:09:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok! Eu estou aguardando um retorno, pois tem um pessoal formando um grupo de 30 pessoas para conseguir desconto na mensalidade, mas queria saber mais informações.","time":"20/02/2026 11:10:35"},{"role":"agent","text":"*Thayanne Sales:* Ok","time":"20/02/2026 11:11:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"20/02/2026 11:11:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Só isso mesmo, obrigada!","time":"20/02/2026 11:11:27"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia.","time":"20/02/2026 11:11:40","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAmanda Rangel Mendonça, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 11:11:44"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/02/2026 11:11:45"},{"role":"client","text":"4","time":"20/02/2026 11:12:04"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"20/02/2026 11:12:06"},{"role":"client","text":"2","time":"20/02/2026 11:12:27"},{"role":"client","text":"Amanda Rangel Mendonça, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"20/02/2026 11:12:28"}]$tag$, $tag$2026-02-20 10:58:21+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$3404590d-f72a-4bf2-9643-89506be76994$tag$, $tag$2026022000073$tag$, $tag$RANGARIRANHE (258867047439)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Quando é que termina o modulo 1","time":"20/02/2026 11:18:45"},{"role":"client","text":"🌟 Bom dia RANGARIRANHE! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 11:18:46"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 11:18:49"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 11:18:53"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 11:19:00"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 11:19:47"},{"role":"client","text":"Olá! RANGARIRANHE!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 11:19:48"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 11:19:52"},{"role":"client","text":"Saber sobre os cursos","time":"20/02/2026 11:20:35"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/02/2026 11:20:39"},{"role":"client","text":"Pós-Graduação","time":"20/02/2026 11:20:53"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"20/02/2026 11:20:56"},{"role":"client","text":"Missiologia Urbana","time":"20/02/2026 11:21:15"},{"role":"client","text":"Aprenda a ler, servir e transformar as cidades com o Evangelho.\n 🏙️ Curso inovador com foco em missão no contexto urbano\n 🎯 Ideal para plantadores de igrejas, missionários e líderes urbanos\n 🕊️ Aulas online com mentoria prática\n","time":"20/02/2026 11:21:16"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/02/2026 11:21:21"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/02/2026 11:21:49"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/02/2026 11:21:50"},{"role":"client","text":"Certo","time":"20/02/2026 11:24:33"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/02/2026 13:26:38"},{"role":"agent","text":"*Karina Pimentel:* *Pós-Graduação em Missiologia Urbana*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n\n  *Missiologia Urbana* - Disciplinas do Curso:\n\nESPIRITUALIDADE MISSIONAL E CULTURA\n1 Teologia e Prática da Espiritualidade (Dr. Valdir Steuernagel e Dr. Tom White)\n2 Teologia da Missão Urbana (Dr. Sérgio Lyra e Dr. Mac Pier)\n3 Contextualização do Evangelho e da Cultura (Miss. Leandro Silva)\n\nMISSÃO E INTEGRALIDADE\n4 Missão Integral (Dr Chris Wright e Miss. Leandro Silva)\n5 Etnografia dos Grupos Urbanos (Dr Mark Matlock e Esp. Renildo Diniz)\n6 Eclesiologia Missional (Ms Valtenci Oliveira)\n\nMISSIONALIDADE, TRANSFORMAÇÃO E CIDADANIA\n7 Fé, Política e Cidadania (Davi Lago)\n8 Justiça, Pobreza e Transformação (Dr N. T. Wright e Ms Bebeto Araújo)\n9 Igreja e Meio-Ambiente (Esp. José Marcos da Silva)\n\nGESTÃO MISSIONAL\n10 Liderança Missional Urbana (Dr. Sérgio Queiroz)\n11 Captação de Recursos para Projetos Sociais (Ms Rafael Bandeira)\n12 Elaboração de Projetos Missionais Urbanos (Esp. Lisania Pereira)\n\nObs: Professores sujeitos a alterações.\n\nO valor de investimento na Pós-graduação em Missiologia Urbana está em 16 mensalidades de *R$ 359,37*. Esse mês esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.","time":"20/02/2026 13:28:19","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obrigado","time":"20/02/2026 13:53:16"},{"role":"agent","text":"*Karina Pimentel:* 📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"","time":"20/02/2026 18:37:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Enviado acima o link para inscrição!","time":"20/02/2026 18:37:51","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estamos a disposição!","time":"20/02/2026 18:38:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"20/02