INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$14c07238-dd2d-4fba-a338-15f68b4556d4$tag$, $tag$2026022000110$tag$, $tag$Antonio Neto (5583996413959)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"20/02/2026 13:14:15"},{"role":"client","text":"🌟 Boa tarde Antonio Neto! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 13:14:16"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 13:14:20"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 13:14:23"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/02/2026 13:14:27"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/02/2026 13:14:33"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/02/2026 13:14:39"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/02/2026 13:14:40"},{"role":"client","text":"Sim, concordo","time":"20/02/2026 13:15:51"},{"role":"client","text":"✅ Obrigado, Antonio Neto! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"20/02/2026 13:15:52"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 13:15:56"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 13:16:30"},{"role":"client","text":"Olá! Antonio Neto!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 13:16:31"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 13:16:35"},{"role":"client","text":"Falar com um atendente","time":"20/02/2026 13:20:36"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"20/02/2026 13:20:37"},{"role":"client","text":"Sobre os cursos","time":"20/02/2026 13:24:31"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/02/2026 13:44:22"},{"role":"client","text":"Olá tudo bem?","time":"20/02/2026 13:44:43"},{"role":"client","text":"Sou o Antônio","time":"20/02/2026 13:44:48"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"20/02/2026 13:44:53","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"client","text":"Eu sou bacharel em teologia no curso livre no instituto teológico Renascer. \n\nEu gostaria de saber se eu poderia fazer alguma capacitação, e quais vcs teriam disponíveis","time":"20/02/2026 13:45:53"},{"role":"agent","text":"*Karina Pimentel:* Sem tem qualquer graduação que seja, reconhecida pelo MEC, a Pós ficará como um curso livre!","time":"20/02/2026 14:04:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* PÓS GRADUAÇÕES: Liderança Cristã, Educação Cristã Clássica, Novo Testamento, Teologia Sistemática, Missiologia Urbana, Ciência Politica e Atuação Pública, Gestão Escolar, Psicopedagogia e Psicoteologia.","time":"20/02/2026 14:04:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6998942e6350dd74460efc9b)","time":"20/02/2026 14:04:46"},{"role":"client","text":"Quanto está a mensalidade da pós teologia do novo testamento","time":"20/02/2026 14:08:49"},{"role":"client","text":"Quais professores?","time":"20/02/2026 14:09:15"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n\n  *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\nTeologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações.\n\nO valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nAo pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. ","time":"20/02/2026 14:11:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Professores de Novo Testamento: Prof Jorge Issao , Prof Elton Carvalho, Prof Gaspar de Sousa, Prof Leonardo Paulino , Luiz Sayão , Prof Emilio Garofalo, Prof Willian Orlandi, Prof Marcus Vinicius de Freitas, Prof Rodrigo de Galiga e Prof Ricardo Aragão!\n","time":"20/02/2026 14:11:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Esse valor é no boleto?","time":"20/02/2026 14:20:05"},{"role":"agent","text":"*Karina Pimentel:* Boleto, Pix ou Cartão.","time":"20/02/2026 14:22:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Tem umas pós em teologia do antigo testamento tbm ?","time":"20/02/2026 15:06:17"},{"role":"agent","text":"*Karina Pimentel:* No momento não temos esse curso!","time":"20/02/2026 15:45:58","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAntonio Neto, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/02/2026 08:22:48"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"23/02/2026 08:22:49"},{"role":"client","text":"Antonio Neto, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"23/02/2026 08:37:51"}]$tag$, $tag$2026-02-20 13:14:15+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 7, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$a14e5b8b-bfa5-4742-847e-649d0232fe46$tag$, $tag$2026022000112$tag$, $tag$Lieverton Melo (5583996511385)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Graça e paz!\n\nFiz o pagamento do boleto das REPOSIÇÕES.","time":"20/02/2026 13:40:49"},{"role":"client","text":"🌟 Boa tarde Lieverton Melo! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 13:40:50"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 13:40:54"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69988e9744390f444506e814)","time":"20/02/2026 13:40:55"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 13:40:56"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 13:41:03"},{"role":"client","text":"Quando será liberada às provas.","time":"20/02/2026 13:41:04"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"20/02/2026 13:41:05"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 13:41:06"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 13:41:12"},{"role":"client","text":"Olá! Lieverton Melo!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 13:41:15"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 13:41:18"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 13:41:18"},{"role":"client","text":"Falar com um atendente","time":"20/02/2026 13:41:31"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"20/02/2026 13:41:31"},{"role":"client","text":"Graça e paz!\n\nFiz o pagamento do boleto das REPOSIÇÕES.","time":"20/02/2026 13:41:41"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69988ed07e854393a704b1d2)","time":"20/02/2026 13:41:52"},{"role":"client","text":"Quando serão liberadas às disciplinas/provas?","time":"20/02/2026 13:42:11"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/02/2026 13:45:44"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe transferir na Secretaria para maiores informações!","time":"20/02/2026 13:46:20","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"20/02/2026 13:46:25"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Tyago Mendes","time":"20/02/2026 14:03:12"},{"role":"client","text":"*Tyago Mendes:* boa tarde, senhor","time":"20/02/2026 14:04:00"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6998940256780ad1bd01657b)","time":"20/02/2026 14:04:02"},{"role":"client","text":"*Tyago Mendes:* reposições liberadas","time":"20/02/2026 14:04:08"},{"role":"client","text":"*Tyago Mendes:* Acessar essas disciplinas com os títulos: REP - referente a reposição","time":"20/02/2026 14:04:24"},{"role":"client","text":"Gratidão!","time":"20/02/2026 14:41:00"},{"role":"client","text":"Quer entender mais sobre a psiquê humana à luz da Teologia?\n\nEstamos lançando a Pós-graduação em Psicoteologia, uma ciência que engloba as áreas do cuidado integral com a teologia para compreender o ser humano de maneira profunda (corpo, mente e espírito). \n\nA proposta é formar profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n\nSe interessou? Acesse agora mesmo nosso site e aproveite a Promoção de Lançamento:\nApenas para os Primeiros Inscritos 50% de Desconto em todo o Curso!\n\n👉 Acesse agora: https://cursos.ficv.edu.br/pos-psicoteologia/","time":"20/02/2026 14:42:27"},{"role":"client","text":"Teria como enviar a grade dessa pós-graduação?","time":"20/02/2026 14:42:41"},{"role":"client","text":"Qual o valor?","time":"20/02/2026 14:42:44"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"20/02/2026 14:57:15"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 15:24:22"},{"role":"client","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"20/02/2026 15:24:31"},{"role":"client","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"20/02/2026 15:24:58"},{"role":"client","text":"*Thayanne Sales:* Disciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"20/02/2026 15:25:20"},{"role":"client","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para Março/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 15:25:27"},{"role":"client","text":"*Thayanne Sales:* Estamos com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"20/02/2026 15:25:49"},{"role":"client","text":"Atendimento Finalizado!\n\nLieverton Melo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/02/2026 08:21:12"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"23/02/2026 08:21:13"},{"role":"client","text":"Lieverton Melo, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"23/02/2026 08:36:14"}]$tag$, $tag$2026-02-20 13:40:49+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bc6a7f84-b00c-40fa-b43b-55649e7f4a26$tag$, $tag$2026022000115$tag$, $tag$Lígia Farias (5583993499418)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"20/02/2026 14:03:02"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"20/02/2026 14:03:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/02/2026 14:08:48"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 \n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!","time":"20/02/2026 14:09:02","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉 \n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/02/2026 14:09:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obgda!","time":"20/02/2026 14:11:44"},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 18:51:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Enviado acima o link para inscrição!","time":"20/02/2026 18:51:41","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"20/02/2026 18:51:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"20/02/2026 18:51:58","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nLígia Farias, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/02/2026 18:52:09"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"23/02/2026 14:09:46"},{"role":"client","text":"Sua sessão expirou!","time":"23/02/2026 14:11:48"}]$tag$, $tag$2026-02-20 14:03:02+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:42:01.563441+00$tag$, 5, 10, 3, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commer