INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2c6b8928-9dbe-4af2-ad07-a07a460f4ea8$tag$, $tag$2026022000149$tag$, $tag$Veridiana Rocha (5547992799229)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Psicoteologia e quero mais informações.","time":"20/02/2026 14:41:57"},{"role":"client","text":"🌟 Boa tarde Veridiana Rocha! Que alegria ter você aqui com a gente! 🙌","time":"20/02/2026 14:41:58"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/02/2026 14:42:02"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/02/2026 14:42:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/02/2026 14:42:13"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/02/2026 14:42:34"},{"role":"client","text":"Olá! Veridiana Rocha!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/02/2026 14:42:35"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/02/2026 14:42:38"},{"role":"client","text":"Saber sobre os cursos","time":"20/02/2026 14:42:56"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/02/2026 14:42:59"},{"role":"client","text":"Pós-Graduação","time":"20/02/2026 14:43:12"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"20/02/2026 14:43:16"},{"role":"client","text":"Psicoteologia","time":"20/02/2026 14:43:31"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"20/02/2026 14:43:32"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/02/2026 14:43:36"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/02/2026 14:43:51"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/02/2026 14:43:51"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"20/02/2026 14:46:39"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"20/02/2026 14:47:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Obrigada!","time":"20/02/2026 14:48:22"},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"20/02/2026 14:48:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Disciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"20/02/2026 14:48:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para Março/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"20/02/2026 14:48:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Estamos com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"20/02/2026 14:49:05","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Esse desconto é o que foi oferecido para alunos que estavam na live de ontem?","time":"20/02/2026 14:50:36"},{"role":"agent","text":"*Thayanne Sales:* Sim","time":"20/02/2026 14:52:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigada!","time":"20/02/2026 14:55:28"},{"role":"client","text":"Vou analisar e te retorno!","time":"20/02/2026 14:55:36"},{"role":"agent","text":"*Thayanne Sales:* ok","time":"20/02/2026 14:56:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Thayanne, bom dia!","time":"21/02/2026 12:09:43"},{"role":"client","text":"Tudo bem?","time":"21/02/2026 12:09:53"},{"role":"client","text":"Me tira uma dúvida, eu posso realizar o pagamento da mensalidade com cartão de crédito? Igual na graduação que existe a osdibiludade de boleto e/ou o cartão de crédito, pode ser?","time":"21/02/2026 12:11:03"},{"role":"client","text":"Outra coisa, essa condição especial é para ex-aluno, como te disse conclui a graduação em 2025 e a colação será 20/03, certo?!","time":"21/02/2026 12:12:02"},{"role":"client","text":"Ela estará disponível ainda no primeiro dia útil do março? Posto realizar minha matrícula no dia 03 de março, no ato da matrícula efetuo o pagamento da mensalidade já com desconto, isso?!","time":"21/02/2026 12:13:25"},{"role":"client","text":"Aguardo seu retorno!🙏🏻","time":"21/02/2026 12:13:33"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"23/02/2026 08:24:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia!","time":"23/02/2026 08:55:33"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia!\n\nNão temos atendimento nos finais de semana e por isso estou lhe retornando hoje","time":"23/02/2026 08:58:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* No caso do cartão de crédito, só está disponível para o pagamento integral do semestre, podendo ser parcelado. Mas mês a mês como era antes não. ","time":"23/02/2026 08:59:18","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Sim! Eu imaginei😉","time":"23/02/2026 08:59:20"},{"role":"agent","text":"*Thayanne Sales:* Essa condição é sim para alunos e ex-alunos e está liberada até o final do mês","time":"23/02/2026 09:00:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Só boleto então!?","time":"23/02/2026 09:00:05"},{"role":"agent","text":"*Thayanne Sales:* Mas como você precisa até o dia 03, eu posso segurar até lá o desconto. ","time":"23/02/2026 09:00:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Mês a mês temos boleto e pix ","time":"23/02/2026 09:00:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Eu gostaria muito!🙏🏻","time":"23/02/2026 09:00:51"},{"role":"client","text":"Tá bem!","time":"23/02/2026 09:00:57"},{"role":"client","text":"No dia 03/03 nos falamos então!?","time":"23/02/2026 09:01:16"},{"role":"agent","text":"*Thayanne Sales:* Combinado","time":"23/02/2026 09:02:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"23/02/2026 09:02:11","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Obrigada!🙏🏻","time":"23/02/2026 09:02:28"},{"role":"client","text":"Por enquanto não! Até dia 03😉","time":"23/02/2026 09:02:48"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. Até lá!","time":"23/02/2026 09:04:57","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Amém!🙏🏻","time":"23/02/2026 09:05:12"},{"role":"client","text":"Atendimento Finalizado!\n\nVeridiana Rocha, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/02/2026 09:05:21"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"23/02/2026 09:05:23"},{"role":"client","text":"5","time":"23/02/2026 09:05:54"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"23/02/2026 09:05:55"},{"role":"client","text":"2","time":"23/02/2026 09:06:11"},{"role":"client","text":"Veridiana Rocha, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"23/02/2026 09:06:12"}]$tag$, $tag$2026-02-20 14:41:57+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 16, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
